// Validate the target tab and auto-fill the per-tab timestamp column.
// Input item shape: { tab: '<TabName>', row: { <col>: <value>, ... } }
// Output item json = the flattened row columns + `tab` (passed through for the
// Sheets node's sheetName expression; no tab named 'tab' exists so auto-map
// ignores it).
const TIMESTAMP_COLUMN = {
  Loomless: 'created_at',
  JV_Targets: 'created_at',
  Terminator_Loom: 'recorded_at',
  Inbound: 'captured_at',
};

const out = [];
for (const item of $input.all()) {
  const data = item.json || {};
  const tab = data.tab;
  const row = { ...(data.row || {}) };

  if (!Object.prototype.hasOwnProperty.call(TIMESTAMP_COLUMN, tab)) {
    throw new Error(
      `Sub_WriteRowToSheet: unknown tab "${tab}". Must be one of: ` +
        Object.keys(TIMESTAMP_COLUMN).join(', ')
    );
  }

  const tsCol = TIMESTAMP_COLUMN[tab];
  if (!row[tsCol]) {
    // UTC ISO 8601, seconds precision: 2026-06-27T15:30:00Z
    row[tsCol] = new Date().toISOString().replace(/\.\d{3}Z$/, 'Z');
  }

  out.push({ json: { ...row, tab } });
}
return out;

// Return a clean success payload to the calling pipeline.
return $input.all().map((item) => ({
  json: {
    success: true,
    tab: item.json.tab,
    row: item.json,
  },
}));
